import { api } from "../baseurl/baseurl";
import { getLoggedInCid } from "../customer/customer";

export function getCartDeviceId() {
  if (typeof window === "undefined") return "";

  const deviceId = localStorage.getItem("deviceId") || crypto.randomUUID();

  localStorage.setItem("deviceId", deviceId);

  console.log(deviceId);

  return deviceId;
}

export function createCartItem({
  cid = getLoggedInCid(),
  pid = null,
  qty = 1,
  variantId = null,
  offerDiscount = 0,
  divid,
} = {}) {
  return api.post("/cart/create", {
    cid,
    pid,
    divid: divid || getCartDeviceId(),
    qty,
    variantId,
    offerDiscount,
  });
}

export function updateCartItem(id, data = {}) {
  return api.put(`/cart/update/${id}`, {
    cid: data.cid ?? getLoggedInCid(),
    pid: data.pid ?? null,
    divid: data.divid || getCartDeviceId(),
    qty: data.qty ?? 1,
    variantId: data.variantId ?? null,
    offerDiscount: data.offerDiscount ?? 0,
  });
}

export function getCartItems({ cid = getLoggedInCid() } = {}) {
  const divid = getCartDeviceId();

  if (cid) {
    return api.get(`/cart/customer/${cid}`);
  }

  return api.get(`/cart/device/${divid}`);
}
